class Solution:
    def centeredSubarrays(self, nums):
        n = len(nums)
        prefix = [0] * (n + 1)
        for i in range(n):
            prefix[i + 1] = prefix[i] + nums[i]
        count = 0
        for l in range(n):
            for r in range(l, n):
                total = prefix[r + 1] - prefix[l]
                if total in nums[l:r + 1]:
                    count += 1
        return count

