class Solution:
    def centeredSubarrays(self, nums):
        n = len(nums)
        count = 0
        for l in range(n):
            total = 0
            seen = set()
            for r in range(l, n):
                total += nums[r]
                seen.add(nums[r])
                if total in seen:
                    count += 1
        return count

