var centeredSubarrays = function(nums) {
    const n = nums.length;
    let count = 0;
    for (let l = 0; l < n; l++) {
        let total = 0;
        const seen = new Set();
        for (let r = l; r < n; r++) {
            total += nums[r];
            seen.add(nums[r]);
            if (seen.has(total)) count++;
        }
    }
    return count;
};
